CREATE ALGORITHM=UNDEFINED DEFINER=`neolab`@`%` SQL SECURITY DEFINER VIEW `v_ml_sku_snapshot` AS select `p`.`sku` AS `sku`,coalesce(convert(nullif(`tp`.`Item Description`,'') using utf8mb4),nullif(`tp`.`Descripcion_Completa`,''),convert(`p`.`sku` using utf8mb4)) AS `producto`,`tp`.`Marca` AS `marca`,`tp`.`Category` AS `category`,`tp`.`Sub-Category` AS `sub_category`,`tp`.`Product Type` AS `product_type`,`tp`.`CAS Number` AS `cas_number`,`tp`.`fecha_actualizacion` AS `catalog_updated_at`,`p`.`tipo_demanda` AS `tipo_demanda`,`p`.`lead_time_dias` AS `lead_time_dias`,`p`.`stock_min` AS `stock_min`,`p`.`stock_objetivo` AS `stock_objetivo`,`p`.`moq` AS `moq`,`p`.`multiplo_compra` AS `multiplo_compra`,`p`.`z_servicio` AS `z_servicio`,`p`.`activo` AS `activo`,`f`.`meses_obs_12m` AS `meses_obs_12m`,`f`.`meses_con_venta_12m` AS `meses_con_venta_12m`,`f`.`pct_meses_con_venta_12m` AS `pct_meses_con_venta_12m`,`f`.`demanda_prom_mensual_12m` AS `demanda_prom_mensual_12m`,`f`.`sigma_mensual_12m` AS `sigma_mensual_12m`,`f`.`p_evento_mensual_12m` AS `p_evento_mensual_12m`,`ef`.`eventos_12m` AS `eventos_12m`,`ef`.`q_evento_12m` AS `q_evento_12m`,`ef`.`sigma_q_evento_12m` AS `sigma_q_evento_12m`,`ef`.`margen_prom_evento_12m` AS `margen_prom_evento_12m`,`ef`.`margen_total_12m` AS `margen_total_12m`,`ef`.`revenue_prom_evento_12m` AS `revenue_prom_evento_12m` from (((`parametros_sku` `p` left join `tablaprecios` `tp` on((`tp`.`Product Number` = `p`.`sku`))) left join `v_sku_features_12m` `f` on((`f`.`SKU` = `p`.`sku`))) left join `v_sku_event_features_12m` `ef` on((`ef`.`SKU` = `p`.`sku`))) where (coalesce(`p`.`activo`,1) = 1)